// ESP32 Blink LED
// ================
// The classic blink sketch running on ESP32.
// Uses the built-in LED on GPIO2 and faster 115200 baud serial.
//
// Circuit: GPIO2 -> 220R -> Red LED -> GND

#include <Arduino.h>

const int LED_PIN = 2;  // GPIO2 (built-in LED on most ESP32 DevKit boards)

void setup() {
  pinMode(LED_PIN, OUTPUT);

  Serial.begin(115200);
  delay(200);

  Serial.println("========================");
  Serial.println("  ESP32 Blink LED Demo");
  Serial.println("========================");
  Serial.println();
  Serial.print("CPU Freq: ");
  Serial.print(getCpuFrequencyMhz());
  Serial.println(" MHz");
  Serial.println("Blinking GPIO2 every 1 second...");
  Serial.println("---");
}

void loop() {
  digitalWrite(LED_PIN, HIGH);
  Serial.println("LED ON");
  delay(1000);

  digitalWrite(LED_PIN, LOW);
  Serial.println("LED OFF");
  delay(1000);
}
